import type { NordicPlatformType } from '../../common/types';

import { getReq } from '@meli/server-context';

const KNOWN_OS = new Set<NordicPlatformType>(['android', 'ios']) as Set<string>;

export function getPlatformType(): NordicPlatformType {
  const { nativeApp } = getReq().device;

  if (!nativeApp) {
    return 'web';
  }

  if (nativeApp.name.toLowerCase() === 'smartpos') {
    return 'smartpos';
  }

  const os = nativeApp.os.toLowerCase();

  if (KNOWN_OS.has(os)) {
    return os as NordicPlatformType;
  }

  return 'web';
}
